import React from 'react';
import { motion } from 'framer-motion';
import { FaCar, FaCarSide } from 'react-icons/fa';
import './Brands.css';

const Brands = () => {
  const brands = [
    { name: 'Proton', logo: 'P', color: '#003366' },
    { name: 'Perodua', logo: 'P2', color: '#cc0000' },
    { name: 'Toyota', logo: 'T', color: '#eb0a1e' },
    { name: 'Honda', logo: 'H', color: '#0072bc' },
    { name: 'Nissan', logo: 'N', color: '#c3002f' },
    { name: 'BMW', logo: 'BMW', color: '#1c69d4' },
    { name: 'Mercedes', logo: 'MB', color: '#00a3e0' },
    { name: 'Mazda', logo: 'M', color: '#101010' },
    { name: 'Mitsubishi', logo: 'MIT', color: '#e60012' },
  ];

  return (
    <section id="brands" className="brands">
      <div className="brands-container">
        <motion.div
          className="section-header"
          initial={{ opacity: 0, y: 30 }}
          whileInView={{ opacity: 1, y: 0 }}
          viewport={{ once: true }}
          transition={{ duration: 0.6 }}
        >
          <span className="section-tag">Our Expertise</span>
          <h2 className="section-title">
            Supported <span className="text-accent">Car Brands</span>
          </h2>
          <p className="section-desc">
            We service all major automotive brands with expert care and precision
          </p>
        </motion.div>

        <div className="brands-grid">
          {brands.map((brand, index) => (
            <motion.div
              key={brand.name}
              className="brand-card"
              initial={{ opacity: 0, y: 30 }}
              whileInView={{ opacity: 1, y: 0 }}
              viewport={{ once: true }}
              transition={{ duration: 0.4, delay: index * 0.1 }}
              whileHover={{ y: -10, scale: 1.02 }}
            >
              <div className="brand-card-inner">
                <div
                  className="brand-logo-circle"
                  style={{ borderColor: brand.color }}
                >
                  <FaCar className="brand-icon" style={{ color: brand.color }} />
                </div>
                <h3 className="brand-name">{brand.name}</h3>
              </div>
              <div
                className="brand-glow"
                style={{ background: brand.color }}
              ></div>
            </motion.div>
          ))}
        </div>
      </div>
      
      <div className="section-divider"></div>
    </section>
  );
};

export default Brands;
